import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import response from './response.json';

interface UpcomingBirthday {
  name: string;
  age: number;
  daysUntil: number;
}

interface BirthdayData {
  upcomingBirthdays: UpcomingBirthday[];
}

export default function Widget() {
  const birthdayData = response.data.data as BirthdayData;
  const theme = response.data.meta.theme;
  const primaryColor = response.data.meta.primaryColor;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 280,
        maxWidth: 400,
        bgcolor: theme === 'light' ? '#FFFFFF' : '#1E293B',
        color: theme === 'light' ? 'text.primary' : '#F8FAFC',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: primaryColor }}>
            Upcoming Birthdays
          </Typography>
          {birthdayData.upcomingBirthdays.map((birthday, index) => (
            <Box key={index}>
              <Typography variant="body1" fontWeight={500}>
                {birthday.name}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Turns {birthday.age} in {birthday.daysUntil} days
              </Typography>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
